// Determine trigger source and set defaults
const items = $input.all();
const triggerNode = $execution.customData?.parentNodeName || '';

let triggerType = 'schedule';
let requestData = {};

// Check if this came from webhook
if (items[0]?.json?.body) {
  triggerType = 'webhook';
  requestData = items[0].json.body;
}

// Defaults
const premise_type = requestData.premise_type || null; // null = auto-select
const vertical = requestData.vertical || 'nutra';
const geo = requestData.geo || 'RU';
const count = requestData.count || (triggerType === 'schedule' ? 3 : 1);

return [{
  json: {
    trigger_type: triggerType,
    premise_type: premise_type,
    vertical: vertical,
    geo: geo,
    count: count,
    auto_select_type: premise_type === null
  }
}];

// Determine final premise_type
const items = $input.all();
const inputData = $('Merge Triggers').first().json;

const VALID_TYPES = ['method', 'discovery', 'confession', 'secret', 'ingredient', 'mechanism', 'breakthrough', 'transformation'];

let targetType = inputData.premise_type;

if (inputData.auto_select_type) {
  // Try to get from RPC result first
  const rpcResult = items.find(i => i.json?.premise_type);
  if (rpcResult) {
    targetType = rpcResult.json.premise_type;
  } else {
    // Fallback: count premises by type from raw data
    const premises = items.filter(i => i.json?.premise_type && VALID_TYPES.includes(i.json.premise_type));
    const typeCounts = {};
    VALID_TYPES.forEach(t => typeCounts[t] = 0);
    premises.forEach(p => {
      if (typeCounts[p.json.premise_type] !== undefined) {
        typeCounts[p.json.premise_type]++;
      }
    });

    // Find type with minimum count
    let minCount = Infinity;
    VALID_TYPES.forEach(t => {
      if (typeCounts[t] < minCount) {
        minCount = typeCounts[t];
        targetType = t;
      }
    });
  }
}

// Validate type
if (!VALID_TYPES.includes(targetType)) {
  targetType = 'method'; // Safe default
}

return [{
  json: {
    premise_type: targetType,
    vertical: inputData.vertical,
    geo: inputData.geo,
    count: inputData.count,
    trigger_type: inputData.trigger_type
  }
}];

// Format LLM prompt
const targetData = $('Determine Target Type').first().json;

// Try to get winning premises, but handle case where node returned empty
let winningPremises = [];
try {
  winningPremises = $('Load Winning Premises').all().map(i => i.json).filter(p => p && p.name);
} catch (e) {
  // Node may not have executed or returned empty
  winningPremises = [];
}

const TYPE_DEFINITIONS = {
  method: 'A specific technique or ritual (e.g., "lemon seed method", "2-minute morning routine")',
  discovery: 'A revelation or finding (e.g., "ancient Tibetan discovery", "accidental lab finding")',
  confession: 'An insider admission (e.g., "doctor\'s confession", "pharma whistleblower")',
  secret: 'Hidden information (e.g., "suppressed remedy", "what they don\'t want you to know")',
  ingredient: 'A specific compound (e.g., "single kitchen ingredient", "forgotten herb")',
  mechanism: 'Root cause explanation (e.g., "hidden trigger", "real reason behind...")',
  breakthrough: 'New research/science (e.g., "Stanford study", "Nobel prize discovery")',
  transformation: 'Change narrative (e.g., "one simple change", "before/after secret")'
};

// Format existing premises for context
let existingContext = 'None available yet.';
if (winningPremises && winningPremises.length > 0) {
  existingContext = winningPremises
    .filter(p => p.name)
    .map(p => `- ${p.name}: ${p.description || 'No description'}`)
    .join('\n');
}

const prompt = `You are a creative copywriter specializing in direct response advertising for health/nutra products.

Generate ${targetData.count} new unique PREMISE concepts of type "${targetData.premise_type}" for ${targetData.vertical} vertical targeting ${targetData.geo} audience.

A premise is a narrative vehicle that makes the product story believable and memorable.

Type definition for "${targetData.premise_type}":
${TYPE_DEFINITIONS[targetData.premise_type]}

All type definitions for reference:
${Object.entries(TYPE_DEFINITIONS).map(([k, v]) => `- ${k}: ${v}`).join('\n')}

Existing premises of this type (avoid duplicates and similar concepts):
${existingContext}

For each premise, provide:
1. name: Short memorable name (5-8 words max, in the language appropriate for ${targetData.geo})
2. origin_story: Where/how this was discovered (2-3 sentences)
3. mechanism_claim: Why this works (1-2 sentences)
4. description: Brief description for internal use (in English)

IMPORTANT: 
- Make each premise unique and distinct from existing ones
- Names should be catchy and memorable
- For RU geo, names and origin_story should be in Russian
- Description and mechanism_claim can be in English

Respond ONLY with valid JSON in this exact format:
{
  "premises": [
    {
      "name": "...",
      "origin_story": "...",
      "mechanism_claim": "...",
      "description": "..."
    }
  ]
}`;

return [{
  json: {
    prompt: prompt,
    premise_type: targetData.premise_type,
    vertical: targetData.vertical,
    geo: targetData.geo,
    count: targetData.count,
    trigger_type: targetData.trigger_type
  }
}];

// Parse LLM response
const llmResponse = $input.first().json;
const context = $('Format LLM Prompt').first().json;

let content = llmResponse.message?.content || llmResponse.content || '';

// Try to parse JSON
let premises = [];
try {
  // Handle if content is already an object
  if (typeof content === 'object' && content.premises) {
    premises = content.premises;
  } else {
    // Parse string content
    const parsed = JSON.parse(content);
    premises = parsed.premises || [];
  }
} catch (e) {
  // Try to extract JSON from text
  const jsonMatch = content.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    try {
      const parsed = JSON.parse(jsonMatch[0]);
      premises = parsed.premises || [];
    } catch (e2) {
      return [{
        json: {
          error: 'Failed to parse LLM response',
          raw_content: content,
          context: context
        }
      }];
    }
  }
}

// Validate and enrich each premise
const validPremises = premises
  .filter(p => p.name && p.name.trim().length > 0)
  .map(p => ({
    name: p.name.trim(),
    description: p.description || null,
    origin_story: p.origin_story || null,
    mechanism_claim: p.mechanism_claim || null,
    premise_type: context.premise_type,
    vertical: context.vertical,
    geo: context.geo,
    source: 'llm_generated',
    status: 'emerging'
  }));

if (validPremises.length === 0) {
  return [{
    json: {
      error: 'No valid premises generated',
      raw_premises: premises,
      context: context
    }
  }];
}

return validPremises.map(p => ({ json: p }));

// Track created premise ID for response
const insertedPremise = $('Insert Premise').first().json;
return [{
  json: {
    created_id: insertedPremise[0]?.id || insertedPremise.id,
    name: insertedPremise[0]?.name || insertedPremise.name,
    premise_type: insertedPremise[0]?.premise_type || insertedPremise.premise_type,
    status: 'created'
  }
}];

// Track skipped (duplicate) premise
const premise = $('Loop Premises').item.json;
return [{
  json: {
    name: premise.name,
    premise_type: premise.premise_type,
    status: 'skipped_duplicate'
  }
}];

// Build response
const results = $input.first().json.results || [];

const created = results.filter(r => r.status === 'created');
const skipped = results.filter(r => r.status === 'skipped_duplicate');

const response = {
  success: true,
  created_count: created.length,
  skipped_count: skipped.length,
  created_ids: created.map(r => r.created_id),
  created_premises: created.map(r => ({
    id: r.created_id,
    name: r.name,
    premise_type: r.premise_type
  })),
  skipped_premises: skipped.map(r => r.name)
};

return [{ json: response }];

